sql:
SELECT cf_id, outcome
FROM campaigns
WHERE pledged >= goal;

external_knowledge:
- A 'generous supporter' is someone who has pledged more than $100;
- 'Recent campaigns' refer to those launched within the last year;
- The total amount pledged by a backer is the sum of all their individual pledges.

sql:
SELECT SQRT(goal) AS sqrt_goal
FROM campaigns
WHERE cf_id = 1;

SELECT subcategories.subcategory_name, categories.category_name
FROM subcategories
JOIN categories ON subcategories.category_id = categories.category_id;

SELECT reward_name
FROM rewards
WHERE reward_name LIKE '%Special%';

SELECT COUNT(*)
FROM campaign_analytics
WHERE backer_count <= 10;

SELECT cf_id, company_name, pledged
FROM campaigns
WHERE pledged > (SELECT AVG(pledged) FROM campaigns);

SELECT cf_id, backers_count, pledged
FROM campaigns
WHERE outcome = 'failed';

SELECT country, COUNT(cf_id) AS campaign_count
FROM campaigns
GROUP BY country;

SELECT backer_name, COUNT(DISTINCT cf_id) AS number_of_campaigns
FROM backers
GROUP BY backer_name;
